import React from "react";
import { Chip } from "@mui/material";

const skills = [
  ["🌐 HTML", "🎨 CSS", "⚡ JavaScript"],
  ["🛠️ TypeScript", "⚛️ React", "📱 React Native"],
  ["🐍 Django", "🐍 Python", "☁️ Azure"],
  ["📡 Share Hosting", "🌊 Digital Ocean"],
  ["🍏 Mac", "🖥️ Windows", "🐧 Linux"]
];

export default function Skills() {
  return (
    <div
      style={{
        textAlign: "center",
        backgroundColor: "#121212",
        color: "white",
        padding: "40px 20px",
        borderRadius: "10px",
        maxWidth: "600px",
        margin: "auto"
      }}
    >
      <h2 style={{ fontSize: "32px", marginBottom: "20px" }}>💻 My Skills</h2>
      <div>
        {skills.map((row, rowIndex) => (
          <div
            key={rowIndex}
            style={{
              display: "flex",
              justifyContent: "center",
              gap: "10px",
              marginBottom: "10px"
            }}
          >
            {row.map((skill, index) => (
              <Chip
                key={index}
                label={skill}
                style={{
                  backgroundColor: "#333",
                  color: "white",
                  fontSize: "16px",
                  fontWeight: "bold",
                  padding: "10px",
                  cursor: "pointer"
                }}
              />
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}
